let env = msg.payload;
let commands = [];

// Kural 1: Kabin Nemi %60'ı geçerse Nem Toplayıcıyı (Dehumidifier) aç
if (env.chamber_humidity > 60.0) {
    commands.push({ payload: { "device": "dehumidifier", "action": true } });
} else if (env.chamber_humidity < 50.0) {
    commands.push({ payload: { "device": "dehumidifier", "action": false } });
}

// Kural 2: Sıcaklık artarsa Fanı aç
if (env.chamber_temperature > 24.5) {
    commands.push({ payload: { "device": "ventilation_fan", "action": true } });
} else if (env.chamber_temperature < 23.5) {
    commands.push({ payload: { "device": "ventilation_fan", "action": false } });
}

return [commands];

// Eski sıcaklık verisini alıyoruz (Yoksa 23 varsayıyoruz)
let temp = msg.payload.Temp_degC_ISS || 23.0;

// 3 bitki için ortak yaşam (Sweet Spot) pH ve EC simülasyonu
let current_pH = (5.8 + (Math.random() * 0.4 - 0.2)).toFixed(2);
let current_EC = (1.5 + (Math.random() * 0.3 - 0.15)).toFixed(2);

let status = "✅ OPTİMAL: 3'lü Ekosistem Stabil";
let color = "#00ff00";

if (current_EC < 1.4) {
    status = "⚠️ MİNERAL DÜŞÜK: EC Pompası Devrede";
    color = "#ffaa00";
} else if (current_pH > 6.0) {
    status = "⚠️ pH YÜKSEK: Asit Dozajı Yapılıyor";
    color = "#ff0000";
} else if (temp > 23.4) {
    status = "⚠️ SICAKLIK KRİTİK: Fanlar Açık";
    color = "#ff0000";
}

// Tüm verileri tek bir pakette birleştir (Web sitesi için)
msg.payload.pH_Level = Number(current_pH);
msg.payload.EC_Level = Number(current_EC);
msg.payload.SystemStatus = status;
msg.color = color;

// 1. Çıkış: WebSocket (Tüm veriler)
// 2. Çıkış: pH Göstergesi
// 3. Çıkış: EC Göstergesi
// 4. Çıkış: Durum Metni
return [
    msg, 
    {payload: msg.payload.pH_Level}, 
    {payload: msg.payload.EC_Level}, 
    {payload: status, color: color}
];
